import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import sailpoint.object.Bundle;
import sailpoint.object.Filter;
import sailpoint.object.Identity;
import sailpoint.object.IdentityEntitlement;
import sailpoint.object.QueryOptions;
import sailpoint.tools.GeneralException;
import sailpoint.tools.Util;
import java.io.File;
import java.io.FileWriter;
import java.io.BufferedWriter;
import java.text.SimpleDateFormat;
//import java.util.Date;


Iterator iterator = null;
BufferedWriter writer = null;
List roleDivisions = null;

try {

  String inputData = (String) config.get("roleCriticality");      //Replace roleCriticality with roleDivision
  roleDivisions = new ArrayList();

  if (!Util.isNullOrEmpty(inputData)) {
    if (inputData.contains(",")) {
      roleDivisions = Arrays.asList(inputData.split(","));
    } else {
      roleDivisions.add(inputData);
    }
  }

  /*if(roleDivisions.isEmpty() || roleDivisions.size()<1) {
    roleDivisions.add("Medium");
    roleDivisions.add("High");
  }*/


  SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd_HH-mm-ss");
  String fileName = "Role Membership Report by RoleDivision_" + sdf.format(new Date()) +".csv";
  File file = new File("D:\\tmp\\" + fileName);

  Filter baseFilter = Filter.and(Filter.in("name", Arrays.asList("detectedRoles","assignedRoles")),Filter.notnull("value"));
  Filter subqueryFilter = Filter.subquery("value", Bundle.class, "name", 	Filter.ignoreCase(Filter.in("Bundle.roleCriticality",roleDivisions)));
  Filter joinFilter = Filter.join("value", "Bundle.name");
  QueryOptions options = new QueryOptions();
  options.addFilter(Filter.and(baseFilter,subqueryFilter,joinFilter));

  String properties = "identity.name,identity.firstname,identity.lastname,identity.department,Bundle.name,name,Bundle.owner.name";
  iterator = context.search(IdentityEntitlement.class, options, properties);
  writer = new BufferedWriter(new FileWriter(file));
  writer.write("IdentityName,FirstName,LastName,Department,RoleName,RoleType,RoleOwner,RoleDescription,RoleDivision,RoleLogicalAppName");
 // writer.newLine();

  String identityName = "";
  String firstName = "";
  String lastName = "";
  String department = "";
  String roleName = "";
  String roleType = "";
  String roleOwner = "";
  String roleDescription = "";
  String roleDivision = "";
  String roleLogicalAppName = "";

  Identity identityObj = null;

  while (iterator.hasNext()) {

    Object[] row = (Object[]) iterator.next();

    identityName = Util.otos(row[0]);
    firstName = Util.otos(row[1]);
    lastName = Util.otos(row[2]);
    department = Util.otos(row[3]);
    roleName = Util.otos(row[4]);

    Bundle bundle = context.getObjectByName(Bundle.class, roleName);
    if (bundle != null) {
      roleDescription = bundle.getDescription("en_US");
      Map sysDescriptions = (Map) bundle.getAttribute("sysDescriptions");
      if (sysDescriptions != null) {
        roleDescription = Util.otos(sysDescriptions.get("en_US"))!=null?Util.otos(sysDescriptions.get("en_US")):"";
      }
      roleDivision =  bundle.getAttribute("roleLevel")!=null?bundle.getAttribute("roleLevel"):"";                     // bundle.getAttribute("RoleDivision");
      roleLogicalAppName = bundle.getAttribute("roleCriticality")!=null?bundle.getAttribute("roleCriticality"):"";          // bundle.getAttribute("appName");
    }
    roleType = Util.otos(row[5]);
    roleOwner = Util.otos(row[6]);

    writer.newLine();
    writer.write(identityName + "," +firstName + "," +lastName + "," +department + "," +roleName + "," +roleType + "," +roleOwner + "," +roleDescription + "," +roleDivision + "," +roleLogicalAppName);

  }
  writer.flush();
} catch (Exception e) {

  if(roleDivisions.isEmpty() || roleDivisions.size()<1) {
    throw new GeneralException("No roleDivision values found from Run Rule Task");
  }
  log.error("Exception in ReportsData1 : ", e);
} finally {
  Util.flushIterator(iterator);
  if (writer != null) {
    writer.close();
  }
}

return "IIQ";
